def main():
    data = json.loads(COURSE_PATH.read_text())
    slug_to_learn = LEARN
    updated = 0
    for unit in data["units"][15:18]:  # Units 16, 17, 18
        for topic in unit["topics"]:
            if topic["slug"] in slug_to_learn:
                topic["learn"] = slug_to_learn[topic["slug"]]
                updated += 1
    COURSE_PATH.write_text(json.dumps(data, indent=2, ensure_ascii=False))
    print(f"Updated {updated} topics with learn content.")

if __name__ == "__main__":
    main()
